import React, { useEffect, useState, useMemo } from 'react';
import { supabase } from '../services/supabaseClient';
import { 
  PiggyBank, AlertCircle, ArrowUpCircle, Target, 
  Calendar, TrendingUp, X, ArrowDownCircle, CheckCircle2, Info, Settings2
} from 'lucide-react';
import '../styles/Orcamento.css';

const Orcamento = () => {
  const [loading, setLoading] = useState(true);
  const [modalDetalhe, setModalDetalhe] = useState({ aberto: false, tipo: '', dados: [] });
  const [dados, setDados] = useState({
    metaReceita: 0,
    receitaReal: 0,
    metaGasto: 0,
    gastoReal: 0,
    categoriasDespesa: [],
    objetivosPessoais: [],
    proventosDetalhados: [],
    resumo503020: {
      essenciais: { valor: 0, limite: 0 },
      estiloVida: { valor: 0, limite: 0 },
      prioridades: { valor: 0, limite: 0 }
    }
  });

  useEffect(() => {
    buscarDadosCompletos();
  }, []);

  const formatMoney = (v) => {
    return (Number(v) || 0).toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' });
  };

  async function buscarDadosCompletos() {
    setLoading(true);
    try {
      const agora = new Date();
      const ano = agora.getFullYear();
      const mes = agora.getMonth() + 1;
      const primeiroDia = `${ano}-${String(mes).padStart(2, '0')}-01`;
      const ultimoDia = new Date(ano, mes, 0).toISOString().split('T')[0];

      const [
        { data: metasData },
        { data: proventos },
        { data: comprasVariaveis },
        { data: parcelasMes },
        { data: cats }
      ] = await Promise.all([
        supabase.from('metas').select('*').eq('mes_referencia', mes).eq('ano_referencia', ano),
        supabase.from('proventos').select('*').gte('data_recebimento', primeiroDia).lte('data_recebimento', ultimoDia),
        supabase.from('compras').select('valor_total, categoria_id').gte('data_compra', primeiroDia).lte('data_compra', ultimoDia),
        supabase.from('parcelas').select('valor_parcela, compras!inner(categoria_id)').gte('data_vencimento', primeiroDia).lte('data_vencimento', ultimoDia),
        supabase.from('categorias').select('*').order('nome', { ascending: true })
      ]);

      const gastosPorCat = {};
      comprasVariaveis?.forEach(c => gastosPorCat[c.categoria_id] = (gastosPorCat[c.categoria_id] || 0) + Number(c.valor_total));
      parcelasMes?.forEach(p => {
        const catId = p.compras?.categoria_id;
        if (catId) gastosPorCat[catId] = (gastosPorCat[catId] || 0) + Number(p.valor_parcela);
      });

      const totalReceitaReal = proventos?.reduce((acc, cur) => acc + Number(cur.valor), 0) || 0;
      const totalGastoReal = Object.values(gastosPorCat).reduce((a, b) => a + b, 0);
      
      const todasCategoriasConsolidadas = (cats || []).map(cat => {
        const metaEncontrada = metasData?.find(m => m.categoria_id === cat.id);
        return {
          ...cat,
          gastoReal: Number(gastosPorCat[cat.id] || 0),
          metaValor: metaEncontrada ? Number(metaEncontrada.valor_meta) : 0,
          tipoMeta: metaEncontrada?.tipo_meta || 'despesa',
        };
      });

      const metaRec = metasData?.filter(m => m.tipo_meta === 'provento').reduce((a, b) => a + Number(b.valor_meta), 0) || 0;

      setDados({
        metaReceita: metaRec,
        receitaReal: totalReceitaReal,
        metaGasto: totalReceitaReal, // Teto dinâmico baseado no que entrou
        gastoReal: totalGastoReal,
        categoriasDespesa: todasCategoriasConsolidadas.filter(c => c.tipo === 'despesa' && c.tipoMeta !== 'pessoal'),
        objetivosPessoais: todasCategoriasConsolidadas.filter(c => c.tipoMeta === 'pessoal'),
        proventosDetalhados: proventos || [],
        resumo503020: calcular503020(totalReceitaReal, todasCategoriasConsolidadas)
      });
    } catch (err) { console.error(err); } finally { setLoading(false); }
  }

  function calcular503020(receita, categorias) {
    const res = {
      essenciais: { valor: 0, limite: receita * 0.5 },
      estiloVida: { valor: 0, limite: receita * 0.3 },
      prioridades: { valor: 0, limite: receita * 0.2 }
    };
    const essenciaisLista = ['Aluguel', 'Saúde', 'Educação', 'Mercado', 'Transporte', 'Água', 'Luz', 'Moradia'];
    categorias.forEach(cat => {
      if (cat.tipoMeta === 'pessoal') res.prioridades.valor += cat.gastoReal;
      else if (essenciaisLista.some(e => cat.nome.includes(e))) res.essenciais.valor += cat.gastoReal;
      else if (cat.tipo === 'despesa') res.estiloVida.valor += cat.gastoReal;
    });
    return res;
  }

  const porcGasto = useMemo(() => dados.metaGasto > 0 ? (dados.gastoReal / dados.metaGasto) * 100 : 0, [dados.gastoReal, dados.metaGasto]);
  const statusConfig = useMemo(() => {
    if (dados.metaGasto === 0 && dados.gastoReal > 0) return { label: 'Gasto sem Receita', class: 'status-bad', color: '#ef4444', icon: <AlertCircle size={14} /> };
    if (dados.metaGasto === 0) return { label: 'Aguardando Proventos', class: 'status-warning', color: '#f59e0b', icon: <Info size={14} /> };
    if (porcGasto <= 85) return { label: 'Tá de boa', class: 'status-good', color: '#10b981', icon: <CheckCircle2 size={14} /> };
    if (porcGasto <= 100) return { label: 'Quase no limite!', class: 'status-warning', color: '#f59e0b', icon: <Info size={14} /> };
    return { label: 'Orçamento Estourado', class: 'status-bad', color: '#ef4444', icon: <AlertCircle size={14} /> };
  }, [porcGasto, dados.metaGasto, dados.gastoReal]);

  return (
    <div className="orcamento-container fade-in">
      {/* HEADER SEMPRE VISÍVEL */}
      <header className="orcamento-header">
        <div className="header-info">
          <h2>Gestão Estratégica</h2>
          <div className="badge-mes">
            <Calendar size={14} />
            <span>{new Intl.DateTimeFormat('pt-BR', { month: 'long' }).format(new Date()).toUpperCase()}</span>
          </div>
        </div>
        <button className="btn-ajuste-premium pulse-primary" onClick={() => window.location.href='/CategoriasMetas'}>
          <Target size={18} /> <span>Definir Metas</span>
        </button>
      </header>

      {loading ? (
        <div className="loading-state">Organizando suas finanças...</div>
      ) : (
        <>
          <section className={`main-stats-card ${statusConfig.class}`}>
            <div className="stats-header">
              <div>
                <span className="stats-label">Gastos vs. Proventos</span>
                <div className="stats-values">
                  <h3>{formatMoney(dados.gastoReal)}</h3>
                  <span className="goal-value">/ {formatMoney(dados.metaGasto)}</span>
                </div>
              </div>
              <div className={`status-icon-main ${statusConfig.class}`} style={{ color: statusConfig.color }}>
                <PiggyBank size={32} />
              </div>
            </div>

            <div className="premium-progress-bg">
              <div 
                className="premium-progress-fill" 
                style={{ width: `${Math.min(porcGasto, 100)}%`, backgroundColor: statusConfig.color }} 
              />
            </div>

            <div className="progress-details">
              <span className="perc-text" style={{ color: statusConfig.color }}>{porcGasto.toFixed(1)}% utilizado</span>
              {dados.gastoReal > dados.metaGasto && <span className="deficit-badge"><AlertCircle size={12}/> Limite Excedido</span>}
            </div>

            <div className={`status-floating-badge ${statusConfig.class}`} style={{ backgroundColor: statusConfig.color }}>
              {statusConfig.icon} {statusConfig.label}
            </div>
          </section>

          {/* GRID DE RESUMOS */}
          <div className="summary-grid-objectives">
            <div className="objective-card-premium clickable" onClick={() => setModalDetalhe({ aberto: true, tipo: 'Receitas', dados: dados.proventosDetalhados })}>
              <div className="obj-header">
                <span className="obj-name"><ArrowUpCircle size={16} color="#10b981" /> Soma de Proventos</span>
              </div>
              <div className="obj-footer">
                <span className="obj-real">{formatMoney(dados.receitaReal)}</span>
              </div>
            </div>

            <div className="objective-card-premium clickable" onClick={() => setModalDetalhe({ aberto: true, tipo: 'Despesas', dados: dados.categoriasDespesa })}>
              <div className="obj-header">
                <span className="obj-name"><ArrowDownCircle size={16} color="#ef4444" /> Total Gasto</span>
              </div>
              <div className="obj-footer">
                <span className="obj-real">{formatMoney(dados.gastoReal)}</span>
              </div>
            </div>
          </div>

          <section className="alocacao-503020">
            <h3 className="premium-section-title">Equilíbrio 50-30-20</h3>
            <div className="alocacao-grid-3-col">
              {['essenciais', 'estiloVida', 'prioridades'].map((key) => {
                const colors = { essenciais: '#3b82f6', estiloVida: '#f59e0b', prioridades: '#8b5cf6' };
                const labels = { essenciais: 'Fixos', estiloVida: 'Desejos', prioridades: 'Futuro' };
                const perc = { essenciais: '50%', estiloVida: '30%', prioridades: '20%' };
                return (
                  <div key={key} className="aloc-mini-card">
                    <span className="aloc-label">{perc[key]} <span className="aloc-sub">{labels[key]}</span></span>
                    <span className="aloc-valor">{formatMoney(dados.resumo503020[key].valor)}</span>
                    <div className="aloc-progress-bg">
                      <div className="aloc-progress-fill" style={{ 
                        width: `${Math.min((dados.resumo503020[key].valor / (dados.resumo503020[key].limite || 1)) * 100, 100)}%`, 
                        backgroundColor: colors[key] 
                      }} />
                    </div>
                  </div>
                );
              })}
            </div>
          </section>
        </>
      )}

      {/* Modais omitidos para brevidade, mas devem permanecer conforme sua versão anterior */}
    </div>
  );
};

export default Orcamento;
